import procfunc as pf
from procfunc.nodes import types as t

from infinigen_v2.generators.util.curve import fillet_mask
from infinigen_v2.generators.util.math import offset_spacing


@pf.nodes.node_function
def staircase_translation(
    input_curve: pf.ProcNode[pf.CurveObject],
) -> pf.ProcNode[pf.CurveObject]:
    # Code generated by procfunc v0.12.0

    input_index = pf.nodes.geo.input_index()

    result_0_selection_a = pf.nodes.math.floor_mod(
        a=input_index.astype(dtype=float), b=2.0
    )
    result_0_selection = pf.nodes.func.equal(
        a=result_0_selection_a.astype(dtype=int), b=1
    )

    input_position = pf.nodes.geo.input_position()

    sample_index_index = input_index.astype(dtype=float) + 1.0
    sample_index = pf.nodes.geo.sample_index(
        clamp=True,
        geometry=input_curve,
        value=input_position.x,
        index=sample_index_index.astype(dtype=int),
    )
    sample = input_index.astype(dtype=float) + -1.0
    sample_index_1 = pf.nodes.geo.sample_index(
        clamp=True,
        geometry=input_curve,
        value=input_position.y,
        index=sample.astype(dtype=int),
    )

    result_0_position = pf.nodes.func.combine_xyz(x=sample_index, y=sample_index_1)

    set_position = pf.nodes.geo.set_position(
        geometry=input_curve,
        selection=result_0_selection,
        position=result_0_position,
    )
    return set_position


@pf.nodes.node_function
def skirting_profile(
    seed: t.SocketOrVal[int],
    count: t.SocketOrVal[int],
    width: t.SocketOrVal[float],
    height: t.SocketOrVal[float],
    fillet_vertices: t.SocketOrVal[int],
    fillet_radius: t.SocketOrVal[float],
    fillet_probability: t.SocketOrVal[float],
    max_offset_pct: t.SocketOrVal[float],
) -> pf.ProcNode[pf.CurveObject]:
    # Code generated by procfunc v0.12.0

    curve_line_start = pf.nodes.math.vector_multiply_add(
        a=(0.0, -1.0, 0.0),
        b=height.astype(dtype=pf.Vector),
        addend=(0.0, 0.0, 0.0),
    )
    curve_line_end = pf.nodes.math.vector_multiply_add(
        a=(-1.0, 0.0, 0.0),
        b=width.astype(dtype=pf.Vector),
        addend=(0.0, 0.0, 0.0),
    )
    curve_line = pf.nodes.geo.curve_line(start=curve_line_start, end=curve_line_end)

    resample = pf.nodes.math.multiply_add(
        a=count.astype(dtype=float), b=2.0, addend=1.0
    )
    resample_curve_count = pf.nodes.geo.resample_curve_count(
        curve=curve_line,
        count=resample.astype(dtype=int),
    )

    input_index = pf.nodes.geo.input_index()

    set_index = pf.nodes.math.floor(input_index.astype(dtype=float) / 2.0)
    set_vertices = count.astype(dtype=float) / 2.0

    offset_spacing_result = offset_spacing(
        seed=seed,
        dimension=width,
        index=set_index.astype(dtype=int),
        vertices=set_vertices.astype(dtype=int),
        max_offset_pct=max_offset_pct,
    )

    set_position_offset = pf.nodes.func.combine_xyz(offset_spacing_result)
    set_position = pf.nodes.geo.set_position(
        geometry=resample_curve_count, offset=set_position_offset
    )

    staircase_translation_result = staircase_translation(input_curve=set_position)

    result_0_selection = pf.nodes.func.random_boolean(
        probability=fillet_probability, seed=seed
    )

    fillet_mask_result = fillet_mask(
        fillet_vertices=fillet_vertices,
        radius=fillet_radius,
        geometry=staircase_translation_result,
        selection=result_0_selection,
    )

    return fillet_mask_result.curve


def skirting_profile_distribution(
    rng: pf.RNG,
    count: int | None = None,
    width: float | None = None,
    height: float | None = None,
    fillet_vertices: int | None = None,
    fillet_radius: float | None = None,
    fillet_probability: float | None = None,
    max_offset_pct: float | None = None,
) -> pf.CurveObject:
    if count is None:
        count = pf.random.randint(rng, 1, 4)
    if height is None:
        height = pf.random.uniform(rng, 0.07, 0.20)
    if width is None:
        width = height * pf.random.uniform(rng, 0.3, 0.6)
    if fillet_vertices is None:
        fillet_vertices = pf.control.choice(rng, [(1, 0.3), (4, 0.7)])
    if fillet_radius is None:
        fillet_radius = pf.random.uniform(rng, 0.01, 0.05)
    if fillet_probability is None:
        fillet_probability = pf.random.uniform(rng, 0.0, 1.0)
    if max_offset_pct is None:
        max_offset_pct = pf.random.uniform(rng, 0.01, 0.05)

    res = skirting_profile(
        seed=pf.random.randint(rng, 0, 1000),
        count=count,
        width=width,
        height=height,
        fillet_vertices=fillet_vertices,
        fillet_radius=fillet_radius,
        fillet_probability=fillet_probability,
        max_offset_pct=max_offset_pct,
    )
    return pf.nodes.to_curve_object(res)
